{
    void Render(nint hdc);
}

internal class DisplayNameEditor : UITypeEditor
{
    public override UITypeEditorEditStyle GetEditStyle(ITypeDescriptorContext? context)
        => UITypeEditorEditStyle.DropDown;

    public override object? EditValue(ITypeDescriptorContext? context, IServiceProvider provider, object? value)
    {
        var svc = provider?.GetService(typeof(IWindowsFormsEditorService)) as IWindowsFormsEditorService;
        if (svc is null) return value;

        var control = CreateDropDown(value);
        // .NET 9 breaking change: DropDownControl(null) now throws ArgumentNullException.
        if (control is not null)
        {
            svc.DropDownControl(control);
            value = control.Text;
        }

        return value;
    }

    private static Control? CreateDropDown(object? currentValue)
    {
        if (currentValue is not string s) return null;
        return new TextBox { Text = s };
    }
}

